          ⏸ Pause
        </button>
        <button className="control-btn next" onClick={handleNext}>
          ⏩ Next
        </button>
        <button className="control-btn restart" onClick={handleRestart}>
          🔄 Restart
        </button>
      </div>
      
      <div className="solution-text montserrat-alternates-regular">
